def knapsack_complete(weights, values, capacity):
    """完全背包：正序遍历，允许无限次选取同一物品"""
    dp = [0] * (capacity + 1)

    for i in range(len(weights)):
        # 关键：正序遍历，允许重复选取
        for j in range(weights[i], capacity + 1):
            dp[j] = max(dp[j], dp[j - weights[i]] + values[i])

    return dp[capacity]

# 恰好装满的初始化技巧
def knapsack_exact_fill(weights, values, capacity):
    """要求背包必须恰好装满时的初始化"""
    dp = [float('-inf')] * (capacity + 1)
    dp[0] = 0  # 容量为0时价值为0，是合法状态

    for i in range(len(weights)):
        for j in range(capacity, weights[i] - 1, -1):
            if dp[j - weights[i]] != float('-inf'):
                dp[j] = max(dp[j], dp[j - weights[i]] + values[i])

    return dp[capacity] if dp[capacity] != float('-inf') else -1

# 多维背包示例：二维费用背包
def knapsack_2d(weight, volume, values, W, V):
    """二维费用背包：同时受重量和体积限制"""
    n = len(weight)
    # dp[j][k] 表示重量不超过j、体积不超过k时的最大价值
    dp = [[0] * (V + 1) for _ in range(W + 1)]

    for i in range(n):
        # 两个维度都需要倒序
        for j in range(W, weight[i] - 1, -1):
            for k in range(V, volume[i] - 1, -1):
                dp[j][k] = max(dp[j][k], 
                              dp[j - weight[i]][k - volume[i]] + values[i])

    return dp[W][V]
